<script setup>import {computed} from 'vue'import {useRouter} from 'vue-router'import trashBin from '@/assets/images/trash-bin.svg'const router = useRouter()const props = defineProps({  todolist: {    type: Array,    required: true,    default: () => [],  },  search: {    type: String,    default: '',  }}) const emit = defineEmits(['delete-todo'])// 검색어 기준 필터링const filteredTodos = computed(() => {  const keyword = props.search.trim().toLowerCase()  if (!keyword) return props.todolist  return props.todolist.filter(todo =>    String(todo.title ?? '').toLowerCase().includes(keyword)  )})// 삭제 이벤트 const onDelete = (id) => {  emit('delete-todo', id)  console.log('자식 컴포넌트에서 삭제 이벤트 보냄')}// 상세페이지 이동 이벤트const goDetail = (id) => {  router.push(`/todo/${id}`)}</script><template>  <ul class ="rows">    <!-- 필터링 전 todo list.만 출력 -->    <li v-for="todo in filteredTodos" :key="todo.id" class="row"      @click="goDetail(todo.id)">        <div class="col title">{{todo.title}}</div>        <div class="col author">{{todo.author}}</div>        <div class="col date">{{todo.createdAt}}</div>        <div class="col actions">          <button class="removeBtn" type="button" @click.stop="onDelete(todo.id)">            <img class="trash" :src="trashBin" alt="삭제" />          </button>        </div>        </li>  </ul></template>